  CLASS
	NAME "Rangos en °C"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "-4 - 0"
    EXPRESSION ([pixel] >= -4 AND [pixel] < 0 )
    COLOR 158 149 252
  END
  CLASS
	NAME "0 - 4"
    EXPRESSION ([pixel] >= 0 AND [pixel] < 4)
    COLOR 200 194 255
  END
  CLASS
	NAME "4 - 8"
    EXPRESSION ([pixel] >= 4 AND [pixel] < 8)
    COLOR 0 255 149
  END
  CLASS
	NAME "8 - 12"
    EXPRESSION ([pixel] >= 8 AND [pixel] < 12)
    COLOR 68 255 0
  END
  CLASS
	NAME "12 - 16"
    EXPRESSION ([pixel] >= 12 AND [pixel] < 16)
    COLOR 204 255 20
  END
  CLASS
	NAME "16 - 20"
    EXPRESSION ([pixel] >= 16 AND [pixel] < 20)
    COLOR 255 255 0
  END
  CLASS
	NAME "20 - 24"
    EXPRESSION ([pixel] >= 20 AND [pixel] <= 24)
    COLOR 230 180 0
  END
END # Layer